'use client';

import { useEffect, useRef } from 'react';
import { motion, AnimatePresence, useReducedMotion } from 'framer-motion';
import Link from 'next/link';
import { usePathname } from 'next/navigation';

interface NavItem {
  label: string;
  href: string;
}

const navItems: NavItem[] = [
  { label: 'Work',     href: '/work' },
  { label: 'Services', href: '/services' },
  { label: 'About',    href: '/about' },
  { label: 'Insights', href: '/insights' },
  { label: 'Contact',  href: '/contact' },
];

interface NavigationMenuProps {
  isOpen: boolean;
  onClose: () => void;
}

export function NavigationMenu({ isOpen, onClose }: NavigationMenuProps) {
  const pathname = usePathname();
  const prefersReducedMotion = useReducedMotion();
  const firstLinkRef = useRef<HTMLAnchorElement>(null);

  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      firstLinkRef.current?.focus();
    } else {
      document.body.style.overflow = '';
    }
    return () => { document.body.style.overflow = ''; };
  }, [isOpen]);

  useEffect(() => { onClose(); }, [pathname]); // eslint-disable-line react-hooks/exhaustive-deps

  const menuVariants = {
    closed: { opacity: 0, y: prefersReducedMotion ? 0 : '-100%' },
    open:   { opacity: 1, y: '0%' },
  };

  const itemVariants = {
    closed: { opacity: 0, y: prefersReducedMotion ? 0 : 32 },
    open:   (i: number) => ({
      opacity: 1,
      y: 0,
      transition: { delay: prefersReducedMotion ? 0 : 0.1 + i * 0.06, duration: 0.5, ease: [0.25, 0.46, 0.45, 0.94] },
    }),
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div
          role="dialog"
          aria-modal="true"
          aria-label="Navigation menu"
          className="fixed inset-0 z-40 flex flex-col bg-black"
          variants={menuVariants}
          initial="closed"
          animate="open"
          exit="closed"
          transition={{ duration: 0.5, ease: [0.76, 0, 0.24, 1] }}
        >
          <div className="container-site flex flex-col justify-end pb-16 pt-32 h-full">
            <nav>
              <ul className="space-y-2">
                {navItems.map((item, i) => (
                  <motion.li
                    key={item.href}
                    custom={i}
                    variants={itemVariants}
                    initial="closed"
                    animate="open"
                    exit="closed"
                  >
                    <Link
                      href={item.href}
                      ref={i === 0 ? firstLinkRef : undefined}
                      className="group block font-display text-display-xl text-white uppercase leading-none hover:text-[#0000FF] transition-colors duration-200"
                    >
                      {item.label}
                    </Link>
                  </motion.li>
                ))}
              </ul>
            </nav>

            <div className="mt-16 border-t border-white/10 pt-8 flex flex-col md:flex-row md:items-center md:justify-between gap-6">
              <div className="flex gap-6 text-sm font-body text-white/50">
                <span>Dubai · Riyadh · Cairo</span>
                <span>Nairobi · Casablanca</span>
              </div>
              <Link href="/contact" className="text-sm font-body font-semibold text-[#0000FF] uppercase tracking-widest hover:text-white transition-colors">
                Start a Project →
              </Link>
            </div>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}
